const aiResponse = $input.first().json;
let prepData = {};
try { prepData = $node["Prepare Data"].json; } catch (e) { prepData = { text: "Unknown", sender: "system" }; }

const rawContent = aiResponse.choices?.[0]?.message?.content || "{}";
let parsed = {};
try {
  const cleanText = rawContent.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleanText);
} catch (e) {
  parsed = { error: "Parse error", raw: rawContent };
}

// Mapeo Maestro para el Dashboard
const catMap = {
  'CAT_MODEL': 'CAT_MODELOS',
  'CAT_CHICAS': 'CAT_MODELOS',
  'CAT_STAFF': 'CAT_PLAZAS',
  'CAT_JOBS': 'CAT_PLAZAS',
  'CAT_OTHER': 'CAT_VARIOS'
};

const rawCat = (parsed.category_key || "CAT_VARIOS").toUpperCase();
const mappedCat = catMap[rawCat] || rawCat;

return {
  categoria: mappedCat,
  plataforma: "TELEGRAM",
  ubicacion: (parsed.location || "Global").toUpperCase(),
  contacto: parsed.contact || "https://t.me/worldmodelsjobs",
  lead_score: parsed.lead_score || 5,
  urgencia: (parsed.urgency_key || "MEDIA").toUpperCase(),
  activa: true,
  translations: {
    "es": { "titulo": parsed.summary_es || "Nueva Oportunidad", "descripcion": "Ver detalles internos." },
    "en": { "titulo": parsed.summary_en || "VIP Casting", "descripcion": "Check internal details." },
    "ru": { "titulo": parsed.summary_ru || "VIP 袣邪褋褌懈薪谐", "descripcion": "袩芯写褉芯斜薪芯褋褌懈 胁 谢械薪褌械." },
    "pt": { "titulo": parsed.summary_pt || "Casting VIP", "descripcion": "Confira os detalles." }
  }
};
